__global__ void compute_step_kernel(const float* f_old, float* f, float* partial_error, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_inner = (n - 2) * (n - 2);

    if (idx < total_inner) {
        int i = (idx % (n - 2)) + 1;
        int j = (idx / (n - 2)) + 1;

        int idx_curr = IDX(i, j);
        int idx_left = IDX(i-1, j);
        int idx_right = IDX(i+1, j);
        int idx_down = IDX(i, j-1);
        int idx_up = IDX(i, j+1);

        float t = 0.25f * (f_old[idx_left] +
